export const columns: ColumnDef<Employee>[] = [
    {
        accessorKey: "name",
        header: ({ column }) => {
            return (
                <button
                    className="flex items-center gap-1 hover:text-[var(--text)] transition-colors"
                    onClick={() => column.toggleSorting(column.getIsSorted() === "asc")}
